50: var ErrUnauthenticated = status.Error(codes.Unauthenticated, "request was not authenticated")
51: 
52: type authenticationContextKey struct{}
53: 
54: // ClientTokenAuthenticator is the minimum subset of an authentication provider
55: // required by the middleware to perform lookups for Authentication instances
56: // using a obtained clientToken.
57: type ClientTokenAuthenticator interface {
58: 	GetAuthenticationByClientToken(ctx context.Context, clientToken string) (*authrpc.Authentication, error)
59: }
