61: // GetAuthenticationFrom is a utility for extracting an Authentication stored
62: // on a context.Context instance
63: func GetAuthenticationFrom(ctx context.Context) *authrpc.Authentication {
64: 	auth := ctx.Value(authenticationContextKey{})
65: 	if auth == nil {
66: 		return nil
67: 	}
68: 
69: 	return auth.(*authrpc.Authentication)
70: }
71: 
72: // ContextWithAuthentication returns a context with the specified authentication
73: func ContextWithAuthentication(ctx context.Context, a *authrpc.Authentication) context.Context {
74: 	return context.WithValue(ctx, authenticationContextKey{}, a)
75: }
