117: // AuthenticationRequiredInterceptor is a grpc.UnaryServerInterceptor which requires that
118: // all requests contain an Authentication instance on the context.
119: func AuthenticationRequiredInterceptor(logger *zap.Logger, o ...containers.Option[InterceptorOptions]) grpc.UnaryServerInterceptor {
120: 	var opts InterceptorOptions
121: 	containers.ApplyAll(&opts, o...)
122: 
123: 	return func(ctx context.Context, req interface{}, info *grpc.UnaryServerInfo, handler grpc.UnaryHandler) (interface{}, error) {
124: 		// skip auth for any preconfigured servers
125: 		if skipped(ctx, info.Server, opts) {
126: 			logger.Debug("skipping authentication for server", zap.String("method", info.FullMethod))
127: 			return handler(ctx, req)
128: 		}
129: 
130: 		auth := GetAuthenticationFrom(ctx)
131: 		if auth == nil {
132: 			logger.Error("unauthenticated", zap.String("reason", "authentication required"))
133: 			return ctx, ErrUnauthenticated
134: 		}
135: 
136: 		return handler(ctx, req)
137: 	}
138: }
