426: func clientTokenFromMetadata(md metadata.MD) (string, error) {
427: 	if authenticationHeader := md.Get(authenticationHeaderKey); len(authenticationHeader) > 0 {
428: 		return fromAuthorization(authenticationHeader[0], authenticationSchemeBearer)
429: 	}
430: 
431: 	cookie, err := cookieFromMetadata(md, middlewarecommon.TokenCookieKey)
432: 	if err != nil {
433: 		return "", err
434: 	}
435: 
436: 	return cookie.Value, nil
437: }
438: 
439: func cookieFromMetadata(md metadata.MD, key string) (*http.Cookie, error) {
440: 	// sadly net/http does not expose cookie parsing
441: 	// outside of http.Request.
442: 	// so instead we fabricate a request around the cookie
443: 	// in order to extract it appropriately.
444: 	return (&http.Request{
445: 		Header: http.Header{"Cookie": md.Get(cookieHeaderKey)},
446: 	}).Cookie(key)
447: }
448: 
449: func jwtFromMetadata(md metadata.MD) (string, error) {
450: 	if authenticationHeader := md.Get(authenticationHeaderKey); len(authenticationHeader) > 0 {
451: 		return fromAuthorization(authenticationHeader[0], authenticationSchemeJWT)
452: 	}
453: 
454: 	return "", ErrUnauthenticated
455: }
456: 
457: func fromAuthorization(auth string, scheme authenticationScheme) (string, error) {
458: 	// Ensure auth is prefixed with the scheme
459: 	if a := strings.TrimPrefix(auth, scheme.String()+" "); auth != a {
460: 		return a, nil
461: 	}
462: 
463: 	return "", ErrUnauthenticated
464: }
